proof_block:
// The ensures clause is `LHS ==> det_set_equal(...)`, so the LHS facts
// are *not* in scope as hypotheses — they have to be unpacked. Wrap the
// proof in an `if` that matches the LHS; inside that branch Verus knows
// the four conjuncts and we can do the transitivity step.
if post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out)
    && post1_self_.wf()
    && post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)
    && post2_self_.wf()
{
    // Both seq@'s are extensionally equal to the same updated sequence,
    // so they are extensionally equal to each other.
    assert(post1_self_.seq@ =~= post2_self_.seq@);
    // Lift extensional equality to structural equality on Seq.
    assert(post1_self_.seq@ == post2_self_.seq@);
    // Ghost<Seq<A>> equality reduces to equality of the inner Seq.
    assert(post1_self_.seq == post2_self_.seq);
    // r1 and r2 are both `()`, trivially equal.
    assert(r1 == r2);
}
